for b in new_books:
    desc_len = len(b['description'])
    if not (125 <= desc_len <= 150):
        errors.append(f"DESC {b['id']} {b['title']}: {desc_len}")
    for i, t in enumerate(b['thoughts']):
        total = len(t['title']) + len(t['example'])
        if not (600 <= total <= 800):
            errors.append(f"  {b['id']} thought {i}: {total} chars")

if errors:
    print("ОШИБКИ:")
    for e in errors: print(" ", e)
else:
    print("Все длины OK!")
